+import { type AnyColumn, Column } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+export type WindowBoundary =
+	| typeof unboundedPreceding
+	| typeof currentRow
+	| typeof unboundedFollowing
+	| { type: 'preceding' | 'following'; value: number };
+
+export interface WindowFrame {
+	type: 'rows' | 'range';
+	from: WindowBoundary;
+	to: WindowBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+export interface WindowDefinition {
+	name: string;
+	spec: WindowSpec;
+}
+
+export const unboundedPreceding = { type: 'unbounded preceding' } as const;
+export const currentRow = { type: 'current row' } as const;
+export const unboundedFollowing = { type: 'unbounded following' } as const;
+
+function offsetBoundary(type: 'preceding' | 'following', value: number): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${type}() requires a non-negative integer, received ${value}`);
+	}
+	return { type, value };
+}
+
+export function preceding(value: number): WindowBoundary {
+	return offsetBoundary('preceding', value);
+}
+
+export function following(value: number): WindowBoundary {
+	return offsetBoundary('following', value);
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	if (boundary === unboundedPreceding) return Number.NEGATIVE_INFINITY;
+	if (boundary === currentRow) return 0;
+	if (boundary === unboundedFollowing) return Number.POSITIVE_INFINITY;
+	return boundary.type === 'preceding' ? -boundary.value : boundary.value;
+}
+
+function createFrame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(spec.from) > boundaryPosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return createFrame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return createFrame('range', spec);
+}
+
+function buildBoundary(boundary: WindowBoundary): SQL {
+	if (boundary === unboundedPreceding || boundary === currentRow || boundary === unboundedFollowing) {
+		return sql.raw(boundary.type);
+	}
+	return sql.raw(`${boundary.value} ${boundary.type}`);
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy ? (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]) : [];
+	const orderBy = spec.orderBy ? (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]) : [];
+	const chunks: SQL[] = [];
+	if (partitionBy.length) chunks.push(sql`partition by ${sql.join(partitionBy, sql`, `)}`);
+	if (orderBy.length) chunks.push(sql`order by ${sql.join(orderBy, sql`, `)}`);
+	if (spec.frame) chunks.push(sql`${sql.raw(spec.frame.type)} between ${buildBoundary(spec.frame.from)} and ${buildBoundary(spec.frame.to)}`);
+	return sql.join(chunks, sql` `);
+}
+
+class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(specOrName: WindowSpec | string): SQL<T> {
+		return typeof specOrName === 'string'
+			? sql`${this.expression} over ${sql.identifier(specOrName)}`
+			: sql`${this.expression} over (${buildWindowSpec(specOrName)})`;
+	}
+
+	getSQL(): SQL<T> {
+		return this.expression;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positionArgument(name: string, value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer, received ${value}`);
+	}
+	return sql.raw(String(value));
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction<number>('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction<number>('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction<number>('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> { return windowFunction<number>('ntile', [positionArgument('ntile', buckets)]); }
+export function percentRank(): WindowFunction<number> { return windowFunction<number>('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction<number>('cume_dist'); }
+
+type ValueType<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+type ValueDecoder<T extends SQLWrapper> = T extends AnyColumn ? T : typeof String;
+function valueFunction<T extends SQLWrapper>(name: string, expression: T, args: SQLWrapper[] = []): WindowFunction<ValueType<T> | null> {
+	return windowFunction<ValueType<T> | null>(name, [expression, ...args]).getSQL().mapWith(is(expression, Column) ? expression : String) as unknown as WindowFunction<ValueType<T> | null>;
+}
+
+export function lag<T extends SQLWrapper>(expression: T, offset?: number): WindowFunction<ValueType<T> | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<ValueType<T>>;
+export function lag(expression: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	const args = [expression, ...(offset === undefined ? [] : [sql.raw(String(offset)])), ...(defaultValue === undefined ? [] : [defaultValue])];
+	return windowFunction('lag', args);
+}
+export function lead<T extends SQLWrapper>(expression: T, offset?: number): WindowFunction<ValueType<T> | null>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<ValueType<T>>;
+export function lead(expression: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	const args = [expression, ...(offset === undefined ? [] : [sql.raw(String(offset)])), ...(defaultValue === undefined ? [] : [defaultValue])];
+	return windowFunction('lead', args);
+}
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<ValueType<T> | null> { return windowFunction('first_value', [expression]); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<ValueType<T> | null> { return windowFunction('last_value', [expression]); }
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunction<ValueType<T> | null> { return windowFunction('nth_value', [expression, positionArgument('nthValue', nth)]); }
+
+export function windowSum(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('sum', [expression]); }
+export function windowAvg(expression: SQLWrapper): WindowFunction<string | null> { return windowFunction('avg', [expression]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<ValueType<T> | null> { return windowFunction('min', [expression]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<ValueType<T> | null> { return windowFunction('max', [expression]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return windowFunction('count', [expression ?? sql.raw('*')]); }
